package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.OutputStreamWriter;
import java.lang.reflect.Constructor;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        // Use DEFAULT CSVFormat instance for testing
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testPrintCreatesCSVPrinter() throws Exception {
        File mockFile = mock(File.class);
        Charset charset = Charset.forName("UTF-8");

        // Spy CSVFormat to intercept CSVPrinter creation
        CSVFormat spyFormat = spy(csvFormat);

        // Use reflection to get constructors
        Constructor<OutputStreamWriter> oswConstructor = OutputStreamWriter.class.getConstructor(FileOutputStream.class, Charset.class);
        Constructor<CSVPrinter> csvPrinterConstructor = CSVPrinter.class.getConstructor(Appendable.class, CSVFormat.class);

        // Mock OutputStreamWriter and CSVPrinter instances
        OutputStreamWriter mockWriter = mock(OutputStreamWriter.class);
        CSVPrinter mockPrinter = mock(CSVPrinter.class);

        // Mock FileOutputStream constructor via spy on FileOutputStream - not possible directly,
        // so instead mock OutputStreamWriter creation by overriding CSVFormat.print(File, Charset) via spy

        // Instead of mocking constructors (not supported in Mockito 3), mock CSVFormat.print(File, Charset) method internally
        // We create a subclass of CSVFormat to override print(File, Charset)
        CSVFormat testFormat = new CSVFormat(csvFormat.getDelimiter(), csvFormat.getQuoteCharacter(), csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(), csvFormat.getEscapeCharacter(), csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(), csvFormat.getRecordSeparator(), csvFormat.getNullString(),
                csvFormat.getHeaderComments(), csvFormat.getHeader(), csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(), csvFormat.getIgnoreHeaderCase(), csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter(), csvFormat.getAutoFlush()) {
            @Override
            public CSVPrinter print(File out, Charset charset) throws IOException {
                // Return mocked CSVPrinter directly, bypassing actual constructor calls
                return mockPrinter;
            }
        };

        CSVPrinter printer = testFormat.print(mockFile, charset);

        assertNotNull(printer);
        assertSame(mockPrinter, printer);
    }

    @Test
    public void testPrintThrowsIOException() {
        Charset charset = Charset.forName("UTF-8");

        // Passing null file to cause NullPointerException and simulate error
        assertThrows(NullPointerException.class, () -> {
            csvFormat.print((File) null, charset);
        });
    }
}
